          highlightedIndex: 0,
          inputValue: '',
          isOpen: true,
          selectedItem: null,
        },
        expect.objectContaining({
          type: stateChangeTypes.InputBlur,
          changes: {
            highlightedIndex: -1,
            inputValue: '',
            isOpen: false,
            selectedItem: null,
          },
        }),
      )
    })
  })

  describe('on focus', () => {
    test('it opens the menu', async () => {
      renderCombobox()

      await tab()

      expect(getItems()).toHaveLength(items.length)
